# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

import flask
import flask_graphql
import graphene

# --- Data Models (In-memory for simplicity) ---

class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category_id = graphene.ID()
    rating = graphene.Float()

class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()

class Review(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user_id = graphene.ID()
    rating = graphene.Int()
    comment = graphene.String()

# --- Mock Data ---
products_db = [
    {"id": "prod1", "name": "Laptop Pro X", "description": "Powerful laptop for professionals", "price": 1200.00, "category_id": "cat1", "rating": 4.5},
    {"id": "prod2", "name": "Wireless Mouse", "description": "Ergonomic and precise", "price": 25.00, "category_id": "cat1", "rating": 4.0},
    {"id": "prod3", "name": "Mechanical Keyboard", "description": "Tactile and responsive", "price": 80.00, "category_id": "cat1", "rating": 4.8},
    {"id": "prod4", "name": "Organic Coffee Beans", "description": "Medium roast, ethically sourced", "price": 15.00, "category_id": "cat2", "rating": 4.7},
    {"id": "prod5", "name": "Herbal Tea Selection", "description": "Assorted herbal teas", "price": 12.00, "category_id": "cat2", "rating": 4.2},
]

categories_db = [
    {"id": "cat1", "name": "Electronics"},
    {"id": "cat2", "name": "Groceries"},
]

reviews_db = [
    {"id": "rev1", "product_id": "prod1", "user_id": "userA", "rating": 5, "comment": "Amazing laptop, super fast!"},
    {"id": "rev2", "product_id": "prod1", "user_id": "userB", "rating": 4, "comment": "Good value for money."},
    {"id": "rev3", "product_id": "prod2", "user_id": "userC", "rating": 4, "comment": "Comfortable mouse."},
    {"id": "rev4", "product_id": "prod4", "user_id": "userA", "rating": 5, "comment": "Best coffee I've ever had."},
    {"id": "rev5", "product_id": "prod4", "user_id": "userD", "rating": 4, "comment": "Good quality, a bit pricey."},
]

# --- GraphQL Schema ---

class Query(graphene.ObjectType):
    products = graphene.List(Product, category_id=graphene.ID(), search=graphene.String())
    product = graphene.Field(Product, id=graphene.ID(required=True))
    categories = graphene.List(Category)
    category = graphene.Field(Category, id=graphene.ID(required=True))
    reviews = graphene.List(Review, product_id=graphene.ID())
    review = graphene.Field(Review, id=graphene.ID(required=True))

    def resolve_products(self, info, category_id=None, search=None):
        filtered_products = products_db
        if category_id:
            filtered_products = [p for p in filtered_products if p["category_id"] == category_id]
        if search:
            search_lower = search.lower()
            filtered_products = [p for p in filtered_products if search_lower in p["name"].lower() or search_lower in p["description"].lower()]
        return [Product(**p) for p in filtered_products]

    def resolve_product(self, info, id):
        product_data = next((p for p in products_db if p["id"] == id), None)
        return Product(**product_data) if product_data else None

    def resolve_categories(self, info):
        return [Category(**c) for c in categories_db]

    def resolve_category(self, info, id):
        category_data = next((c for c in categories_db if c["id"] == id), None)
        return Category(**category_data) if category_data else None

    def resolve_reviews(self, info, product_id=None):
        filtered_reviews = reviews_db
        if product_id:
            filtered_reviews = [r for r in filtered_reviews if r["product_id"] == product_id]
        return [Review(**r) for r in filtered_reviews]

    def resolve_review(self, info, id):
        review_data = next((r for r in reviews_db if r["id"] == id), None)
        return Review(**review_data) if review_data else None

schema = graphene.Schema(query=Query)

# --- Flask App ---
app = flask.Flask(__name__)

@app.route("/graphql", methods=["GET", "POST"])
def graphql_server():
    return flask_graphql.GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True # Enable GraphiQL for easy testing and exploration
    )()

if __name__ == "__main__":
    app.run(debug=True) # Run in debug mode for development